   * @param {number} level - 标题级别 (1, 2, 3)
   * @returns {FeishuBlockBuilder}
   */
  addHeading(text, level = 1) {
    const blockType = level === 1 ? 3 : level === 2 ? 4 : 5;
    const block = {
